import{_ as a,o as l,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"39. Meal Allowances","description":"","frontmatter":{"title":"39. Meal Allowances","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime","shift-work","allowances"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/39-meal-allowances.md","filePath":"ebas/has-managers-admin/common-terms/allowances/39-meal-allowances.md"}'),s={name:"ebas/has-managers-admin/common-terms/allowances/39-meal-allowances.md"};function n(t,e,i,m,h,c){return l(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_39-meal-allowances" tabindex="-1">39. Meal Allowances <a class="header-anchor" href="#_39-meal-allowances" aria-label="Permalink to &quot;39. Meal Allowances&quot;">​</a></h1><p><strong>39.1</strong> Where an Employee is required to work overtime Monday to Friday (inclusive) for more than one hour after the usual finish time, or in the case of shift workers when the overtime exceeds one hour, or on a Saturday/Sunday for more than 5 hours, the Employer will either supply the Employee with an adequate meal or pay a meal allowance.</p><p><strong>39.2</strong> Where such overtime exceeds 4 hours Monday to Friday (inclusive), or 9 hours on a Saturday/Sunday, the Employer will either supply the Employee with a further adequate meal or pay a further meal allowance.</p><p><strong>39.3</strong> The provisions of subclause 39.1 and subclause 39.2 will not apply where the Employee could reasonably return home for a meal within the period allowed.</p><p><strong>39.4</strong> The meal allowances payable over the life of this Agreement are set out in <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> and <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> (as applicable).</p><p><strong>39.5</strong> Claims for payment of an overtime meal allowance will be processed in the next ordinary pay.</p><p>Plain language terms: meal money, meal reimbursement.</p>',7)])])}const u=a(s,[["render",n]]);export{p as __pageData,u as default};
